import React, { useEffect, useState, useCallback } from 'react';
import api from '../utils/api';
import Toast from '../components/Toast';
import { useAuth } from '../hooks/useAuth';

const RECIPIENT_LABELS: any = {
  all: 'All Members',
  students: 'All Students',
  staff: 'All Staff',
  specific: 'Specific Member',
};

export default function Announcements() {
  const { user } = useAuth();
  const isStaff = user?.userType === 'user';

  return isStaff ? <StaffView /> : <MemberView />;
}

/* ─── Librarian / Assistant View ─── */
function StaffView() {
  const { user } = useAuth();
  const [tab, setTab] = useState<'compose' | 'sent'>('compose');
  const [recipientType, setRecipientType] = useState('all');
  const [members, setMembers] = useState<any[]>([]);
  const [memberId, setMemberId] = useState('');
  const [memberSearch, setMemberSearch] = useState('');
  const [subject, setSubject] = useState('');
  const [message, setMessage] = useState('');
  const [sending, setSending] = useState(false);
  const [sent, setSent] = useState<any[]>([]);
  const [loadingSent, setLoadingSent] = useState(false);
  const [toast, setToast] = useState<any>(null);

  const loadMembers = useCallback(async () => {
    try {
      const { data } = await api.get('/members?limit=500&status=active');
      setMembers(data.data || []);
    } catch { setMembers([]); }
  }, []);

  const loadSent = useCallback(async () => {
    setLoadingSent(true);
    try {
      const { data } = await api.get('/announcements/sent');
      setSent(data.data || []);
    } catch { setSent([]); }
    finally { setLoadingSent(false); }
  }, []);

  useEffect(() => { loadMembers(); }, [loadMembers]);
  useEffect(() => { if (tab === 'sent') loadSent(); }, [tab, loadSent]);

  const filteredMembers = members.filter(m =>
    m.name.toLowerCase().includes(memberSearch.toLowerCase()) ||
    m.email.toLowerCase().includes(memberSearch.toLowerCase()) ||
    m.member_id?.toLowerCase().includes(memberSearch.toLowerCase())
  );

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!subject.trim() || !message.trim()) return;
    if (recipientType === 'specific' && !memberId) {
      setToast({ type: 'error', message: 'Please select a member' });
      return;
    }
    setSending(true);
    try {
      const { data } = await api.post('/announcements/send', {
        recipient_type: recipientType,
        member_id: recipientType === 'specific' ? memberId : undefined,
        subject: subject.trim(),
        message: message.trim(),
      });
      setToast({ type: 'success', message: data.message });
      setSubject('');
      setMessage('');
      setMemberId('');
      setMemberSearch('');
    } catch (err: any) {
      setToast({ type: 'error', message: err.response?.data?.message || 'Failed to send' });
    } finally { setSending(false); }
  };

  const cs = {
    page: { padding: '32px', fontFamily: "'DM Sans',sans-serif" },
    title: { fontSize: 26, fontWeight: 800, color: 'var(--text)', margin: '0 0 6px' },
    sub: { fontSize: 14, color: 'var(--text-muted)', margin: '0 0 28px' },
    tabs: { display: 'flex', gap: 4, background: 'var(--card-bg)', border: '1px solid var(--border)', borderRadius: 12, padding: 4, marginBottom: 28, width: 'fit-content' },
    tab: (active: boolean): React.CSSProperties => ({
      padding: '9px 22px', borderRadius: 9, fontSize: 14, fontWeight: 600,
      background: active ? '#c9a84c' : 'transparent',
      color: active ? '#1a1a2e' : 'var(--text-muted)',
      border: 'none', cursor: 'pointer', fontFamily: 'inherit', transition: 'all .18s',
    }),
    card: { background: 'var(--card-bg)', border: '1px solid var(--border)', borderRadius: 16, padding: '28px' },
    label: { display: 'block', fontSize: 12, fontWeight: 700, color: 'var(--text-muted)', marginBottom: 8, letterSpacing: '1px', textTransform: 'uppercase' as const },
    input: { width: '100%', padding: '12px 16px', background: 'var(--input-bg)', border: '1.5px solid var(--border)', borderRadius: 10, fontSize: 14, color: 'var(--text)', fontFamily: 'inherit', outline: 'none', boxSizing: 'border-box' as const },
    select: { width: '100%', padding: '12px 16px', background: 'var(--input-bg)', border: '1.5px solid var(--border)', borderRadius: 10, fontSize: 14, color: 'var(--text)', fontFamily: 'inherit', outline: 'none', cursor: 'pointer', boxSizing: 'border-box' as const },
    btn: { padding: '13px 32px', background: '#c9a84c', color: '#1a1a2e', border: 'none', borderRadius: 11, fontSize: 15, fontWeight: 700, cursor: 'pointer', fontFamily: 'inherit', transition: 'all .2s' },
  };

  return (
    <div style={cs.page}>
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <h1 style={cs.title}>Notifications</h1>
      <p style={cs.sub}>Send announcements to members via email</p>

      <div style={cs.tabs}>
        <button style={cs.tab(tab === 'compose')} onClick={() => setTab('compose')}>✉ Compose</button>
        <button style={cs.tab(tab === 'sent')} onClick={() => setTab('sent')}>📋 Sent History</button>
      </div>

      {tab === 'compose' && (
        <div style={{ maxWidth: 680 }}>
          <div style={cs.card}>
            <form onSubmit={handleSend}>
              {/* Recipient */}
              <div style={{ marginBottom: 20 }}>
                <label style={cs.label}>Send To</label>
                <select value={recipientType} onChange={e => { setRecipientType(e.target.value); setMemberId(''); setMemberSearch(''); }} style={cs.select}>
                  <option value="all">All Active Members</option>
                  <option value="students">All Students</option>
                  <option value="staff">All Staff Members</option>
                  <option value="specific">Specific Member</option>
                </select>
              </div>

              {/* Member search (specific) */}
              {recipientType === 'specific' && (
                <div style={{ marginBottom: 20 }}>
                  <label style={cs.label}>Search Member</label>
                  <input style={cs.input} placeholder="Search by name, email or ID..." value={memberSearch} onChange={e => { setMemberSearch(e.target.value); setMemberId(''); }} />
                  {memberSearch && (
                    <div style={{ marginTop: 6, background: 'var(--card-bg)', border: '1px solid var(--border)', borderRadius: 10, maxHeight: 200, overflowY: 'auto' }}>
                      {filteredMembers.length === 0
                        ? <div style={{ padding: '12px 16px', fontSize: 13, color: 'var(--text-muted)' }}>No members found</div>
                        : filteredMembers.slice(0, 8).map(m => (
                          <div key={m.id} onClick={() => { setMemberId(m.id); setMemberSearch(`${m.name} (${m.member_id})`); }}
                            style={{ padding: '10px 16px', cursor: 'pointer', borderBottom: '1px solid var(--border)', fontSize: 14, color: memberId === m.id ? '#c9a84c' : 'var(--text)', background: memberId === m.id ? 'rgba(201,168,76,0.08)' : 'transparent' }}>
                            <span style={{ fontWeight: 600 }}>{m.name}</span>
                            <span style={{ fontSize: 12, color: 'var(--text-muted)', marginLeft: 8 }}>{m.member_id} · {m.account_type}</span>
                          </div>
                        ))
                      }
                    </div>
                  )}
                  {memberId && !memberSearch.includes('(') && (
                    <p style={{ fontSize: 12, color: '#c9a84c', marginTop: 6 }}>✓ Member selected</p>
                  )}
                </div>
              )}

              {/* Subject */}
              <div style={{ marginBottom: 20 }}>
                <label style={cs.label}>Subject</label>
                <input style={cs.input} placeholder="e.g. Library Maintenance Notice" value={subject} onChange={e => setSubject(e.target.value)} required />
              </div>

              {/* Message */}
              <div style={{ marginBottom: 24 }}>
                <label style={cs.label}>Message</label>
                <textarea style={{ ...cs.input, minHeight: 140, resize: 'vertical', lineHeight: 1.6 }}
                  placeholder="Write your notification message here..." value={message} onChange={e => setMessage(e.target.value)} required />
              </div>

              {/* Preview */}
              <div style={{ background: 'rgba(201,168,76,0.06)', border: '1px solid rgba(201,168,76,0.2)', borderRadius: 10, padding: '12px 16px', marginBottom: 22, fontSize: 13, color: 'var(--text-muted)' }}>
                📧 Will be sent to: <strong style={{ color: '#c9a84c' }}>
                  {recipientType === 'specific' && memberId
                    ? memberSearch
                    : RECIPIENT_LABELS[recipientType]}
                </strong>
              </div>

              <button type="submit" disabled={sending} style={{ ...cs.btn, opacity: sending ? .65 : 1, cursor: sending ? 'not-allowed' : 'pointer' }}>
                {sending ? 'Sending...' : '📢 Send Notification'}
              </button>
            </form>
          </div>
        </div>
      )}

      {tab === 'sent' && (
        <div>
          {loadingSent ? (
            <div style={{ textAlign: 'center', padding: 60, color: 'var(--text-muted)', fontSize: 14 }}>Loading...</div>
          ) : sent.length === 0 ? (
            <div style={{ ...cs.card, textAlign: 'center', padding: 60, color: 'var(--text-muted)' }}>
              <div style={{ fontSize: 40, marginBottom: 12 }}>📭</div>
              <div style={{ fontSize: 15, fontWeight: 600 }}>No notifications sent yet</div>
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              {sent.map(a => (
                <div key={a.id} style={{ ...cs.card, padding: '20px 24px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 16, flexWrap: 'wrap' }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 16, fontWeight: 700, color: 'var(--text)', marginBottom: 4 }}>{a.subject}</div>
                      <div style={{ fontSize: 13, color: 'var(--text-muted)', marginBottom: 10, whiteSpace: 'pre-wrap', lineHeight: 1.6 }}>
                        {a.message.length > 200 ? a.message.slice(0, 200) + '...' : a.message}
                      </div>
                      <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', fontSize: 12 }}>
                        <span style={{ background: 'rgba(201,168,76,0.1)', color: '#c9a84c', padding: '3px 10px', borderRadius: 20, fontWeight: 600 }}>
                          {RECIPIENT_LABELS[a.recipient_type]}
                          {a.recipient_type === 'specific' && a.member_name && `: ${a.member_name}`}
                        </span>
                        <span style={{ color: 'var(--text-muted)' }}>👥 {a.sent_count} recipient(s)</span>
                        <span style={{ color: 'var(--text-muted)' }}>✉ Sent by {a.sent_by_name}</span>
                      </div>
                    </div>
                    <div style={{ fontSize: 12, color: 'var(--text-muted)', whiteSpace: 'nowrap' }}>
                      {new Date(a.sent_at).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' })}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

/* ─── Member View ─── */
function MemberView() {
  const [items, setItems] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get('/announcements/my');
      setItems(data.data || []);
    } catch { setItems([]); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  const markRead = async (inboxId: number) => {
    try {
      await api.put(`/announcements/${inboxId}/read`);
      setItems(prev => prev.map(i => i.inbox_id === inboxId ? { ...i, is_read: 1 } : i));
    } catch {}
  };

  const unread = items.filter(i => !i.is_read).length;

  const cs = {
    page: { padding: '32px', fontFamily: "'DM Sans',sans-serif" },
    card: { background: 'var(--card-bg)', border: '1px solid var(--border)', borderRadius: 16, padding: '20px 24px', marginBottom: 12, cursor: 'pointer' },
  };

  return (
    <div style={cs.page}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 6 }}>
        <h1 style={{ fontSize: 26, fontWeight: 800, color: 'var(--text)', margin: 0 }}>Notifications</h1>
        {unread > 0 && (
          <span style={{ background: '#dc2626', color: '#fff', fontSize: 12, fontWeight: 700, padding: '2px 9px', borderRadius: 99 }}>{unread} new</span>
        )}
      </div>
      <p style={{ fontSize: 14, color: 'var(--text-muted)', margin: '0 0 28px' }}>Messages from library administration</p>

      {loading ? (
        <div style={{ textAlign: 'center', padding: 60, color: 'var(--text-muted)', fontSize: 14 }}>Loading...</div>
      ) : items.length === 0 ? (
        <div style={{ ...cs.card, textAlign: 'center', padding: 60, color: 'var(--text-muted)', cursor: 'default' }}>
          <div style={{ fontSize: 40, marginBottom: 12 }}>📭</div>
          <div style={{ fontSize: 15, fontWeight: 600 }}>No notifications yet</div>
        </div>
      ) : (
        items.map(item => (
          <div key={item.inbox_id} onClick={() => !item.is_read && markRead(item.inbox_id)}
            style={{ ...cs.card, borderLeft: !item.is_read ? '3px solid #c9a84c' : '3px solid transparent', background: !item.is_read ? 'rgba(201,168,76,0.04)' : 'var(--card-bg)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 16 }}>
              <div style={{ flex: 1 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
                  {!item.is_read && <span style={{ width: 8, height: 8, borderRadius: '50%', background: '#c9a84c', display: 'inline-block', flexShrink: 0 }} />}
                  <span style={{ fontSize: 16, fontWeight: item.is_read ? 600 : 700, color: 'var(--text)' }}>{item.subject}</span>
                </div>
                <p style={{ fontSize: 14, color: 'var(--text-muted)', margin: '0 0 10px', lineHeight: 1.6, whiteSpace: 'pre-wrap' }}>{item.message}</p>
                <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>
                  From: <strong style={{ color: '#c9a84c' }}>{item.sent_by_name}</strong>
                </div>
              </div>
              <div style={{ textAlign: 'right', flexShrink: 0 }}>
                <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>
                  {new Date(item.sent_at).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })}
                </div>
                {item.is_read
                  ? <span style={{ fontSize: 11, color: 'var(--text-muted)', marginTop: 4, display: 'block' }}>Read ✓</span>
                  : <span style={{ fontSize: 11, color: '#c9a84c', marginTop: 4, display: 'block', fontWeight: 600 }}>Click to mark read</span>
                }
              </div>
            </div>
          </div>
        ))
      )}
    </div>
  );
}
